/* =============================
   Design System & Resets
   ============================= */

:root {
    /* Brand Palette (extracted / provided) */
    --color-primary-deep: #0B3F36;   /* header/nav background */
    --color-primary-gold: #E0C574;   /* logo gold, dividers */
    --color-primary-gold-soft: #F4D37A; /* status bar, soft accents */
    --color-secondary-navy: #133556; /* deep blue from hero wall */
    --color-accent-green: #0C5A47;   /* buttons / hovers */
    --color-accent-warm: #FF9450;    /* warm accent (lamps) */

    --color-neutral-000: #FFFFFF;
    --color-neutral-050: #F2F2F2;
    --color-neutral-900: #222222;

    --color-success: #1B7D4F;
    --color-error: #BF3B3B;
    --color-warning: #F2B53F;
    --color-info: #0B6E8B;

    /* Typography */
    --font-heading: 'Space Grotesk', Helvetica, Arial, sans-serif;
    --font-body: 'Source Sans 3', Arial, sans-serif;

    --font-size-h1: 40px;
    --font-size-h2: 32px;
    --font-size-h3: 24px;
    --font-size-body: 16px;
    --font-size-small: 13px;

    --font-weight-light: 300;
    --font-weight-regular: 400;
    --font-weight-medium: 500;
    --font-weight-semibold: 600;
    --font-weight-bold: 700;

    --line-height-tight: 1.2;
    --line-height-normal: 1.5;
    --line-height-relaxed: 1.75;

    /* Spacing scale (8px base) */
    --space-1: 4px;
    --space-2: 8px;
    --space-3: 16px;
    --space-4: 24px;
    --space-5: 32px;
    --space-6: 48px;
    --space-7: 64px;

    --radius-sm: 4px;
    --radius-md: 6px;
    --radius-lg: 8px;

    --transition-fast: 150ms ease-out;
    --transition-med: 220ms ease-out;

    --shadow-soft: 0 6px 18px rgba(0, 0, 0, 0.12);
    --shadow-subtle: 0 1px 3px rgba(0, 0, 0, 0.12);

    --layout-max-width: 1120px;
}

* {
    box-sizing: border-box;
}

html,
body {
    margin: 0;
    padding: 0;
}

body.site-body {
    font-family: var(--font-body);
    font-size: var(--font-size-body);
    line-height: var(--line-height-normal);
    color: var(--color-neutral-900);
    background-color: var(--color-neutral-050);
}

img {
    max-width: 100%;
    display: block;
}

a {
    color: inherit;
    text-decoration: none;
}

a:focus-visible,
button:focus-visible {
    outline: 2px solid var(--color-primary-gold);
    outline-offset: 2px;
}

ul,
ol {
    margin: 0;
    padding: 0;
    list-style: none;
}

.layout-width {
    max-width: var(--layout-max-width);
    margin-left: auto;
    margin-right: auto;
    padding-left: var(--space-3);
    padding-right: var(--space-3);
}

/* =============================
   Header
   ============================= */

.site-header {
    background-color: var(--color-primary-deep);
    color: var(--color-neutral-000);
    position: relative;
    z-index: 10;
}

.header-top {
    display: flex;
    align-items: stretch;
}

/* Logo card on the left, echoing the badge-on-gold block */
.header-logo-card {
    background-color: var(--color-primary-deep);
    min-width: 260px;
    max-width: 280px;
    padding: var(--space-3) var(--space-4) var(--space-2);
    position: relative;
}

.header-logo-card::after {
    content: '';
    position: absolute;
    left: 0;
    right: 0;
    bottom: 0;
    height: 36px;
    background-color: var(--color-primary-gold-soft);
}

.brand-link {
    display: block;
    color: var(--color-neutral-000);
    text-decoration: none;
}

.brand-inner {
    position: relative;
    z-index: 1;
}

.brand-badge {
    position: relative;
    padding: var(--space-3) var(--space-3) var(--space-2);
    border-radius: var(--radius-lg);
    border: 1px solid rgba(224, 197, 116, 0.6);
    text-align: center;
    text-transform: uppercase;
    letter-spacing: 0.14em;
    font-family: var(--font-heading);
}

.brand-badge-line {
    position: absolute;
    left: 10%;
    right: 10%;
    border-top: 1px solid rgba(224, 197, 116, 0.5);
}

.brand-badge-line-top {
    top: 10px;
}

.brand-badge-line-bottom {
    bottom: 10px;
}

.brand-name {
    display: block;
    font-size: 18px;
    font-weight: var(--font-weight-semibold);
    margin-bottom: var(--space-1);
}

.brand-subtitle {
    display: block;
    font-size: 11px;
    font-weight: var(--font-weight-regular);
    opacity: 0.85;
}

.brand-phone {
    display: block;
    margin-top: var(--space-2);
    padding-top: var(--space-1);
    font-size: 13px;
    font-weight: var(--font-weight-medium);
    letter-spacing: 0.08em;
    text-transform: uppercase;
    color: var(--color-primary-deep);
}

.header-logo-card .brand-phone {
    position: relative;
    z-index: 1;
}

.header-top-main {
    flex: 1 1 auto;
    display: flex;
    flex-direction: column;
}

.header-top-bar {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding-top: var(--space-2);
    padding-bottom: var(--space-2);
}

.header-top-center {
    flex: 0 0 auto;
}

/* Language switcher (non-interactive placeholders) */
.language-switcher {
    font-family: var(--font-heading);
    font-size: 12px;
    letter-spacing: 0.16em;
    text-transform: uppercase;
    display: flex;
    align-items: center;
    gap: var(--space-1);
    color: rgba(255, 255, 255, 0.9);
}

.language-link {
    opacity: 0.7;
}

.language-link.is-active {
    opacity: 1;
    font-weight: var(--font-weight-semibold);
}

.language-separator {
    opacity: 0.6;
}

/* Main navigation bar */
.header-main {
    border-top: 1px solid rgba(255, 255, 255, 0.06);
    border-bottom: 1px solid rgba(0, 0, 0, 0.35);
    background: linear-gradient(to bottom, #0E4A3F 0%, #0B3F36 70%);
}

.main-nav {
    font-family: var(--font-heading);
}

.nav-list {
    display: flex;
    align-items: center;
    justify-content: flex-end;
    gap: var(--space-4);
    padding-top: var(--space-2);
    padding-bottom: var(--space-2);
}

.nav-item {
    position: relative;
}

.nav-link {
    font-size: 13px;
    letter-spacing: 0.16em;
    text-transform: uppercase;
    font-weight: var(--font-weight-medium);
    color: rgba(255, 255, 255, 0.88);
    padding-bottom: 4px;
    transition: color var(--transition-med), border-color var(--transition-med);
    border-bottom: 2px solid transparent;
}

.nav-link:hover {
    color: var(--color-primary-gold);
    border-bottom-color: rgba(224, 197, 116, 0.85);
}

/* Accent styling for the key CTA-like nav item */
.nav-item-accent {
    padding-left: var(--space-3);
    position: relative;
}

.nav-item-accent::before,
.nav-item-accent::after {
    content: '\2022';
    position: absolute;
    left: 0;
    font-size: 12px;
    color: var(--color-primary-gold);
    top: 50%;
    transform: translateY(-50%);
}

.nav-item-accent::after {
    left: auto;
    right: -12px;
}

.nav-link-accent {
    padding: 6px 10px 4px;
    border-radius: 999px;
    border: 1px solid rgba(224, 197, 116, 0.9);
    color: var(--color-primary-gold);
    font-weight: var(--font-weight-semibold);
}

.nav-link-accent:hover {
    background-color: var(--color-primary-gold);
    color: var(--color-primary-deep);
}

/* =============================
   Main Content Wrapper
   ============================= */

.page-content {
    min-height: 320px;
    padding-top: var(--space-6);
    padding-bottom: var(--space-6);
}

/* =============================
   Footer
   ============================= */

.site-footer {
    background-color: var(--color-primary-deep);
    color: rgba(255, 255, 255, 0.9);
    padding-top: var(--space-5);
    padding-bottom: var(--space-4);
    position: relative;
}

.site-footer::before {
    content: '';
    position: absolute;
    left: 0;
    right: 0;
    top: 0;
    height: 4px;
    background: linear-gradient(to right, var(--color-primary-gold-soft), var(--color-primary-gold));
}

.footer-inner {
    position: relative;
    z-index: 1;
}

.footer-top {
    display: flex;
    flex-direction: column;
    gap: var(--space-4);
}

.footer-brand {
    max-width: 360px;
}

.footer-logo-text {
    font-family: var(--font-heading);
    font-size: 20px;
    letter-spacing: 0.18em;
    text-transform: uppercase;
    font-weight: var(--font-weight-semibold);
    margin-bottom: var(--space-1);
}

.footer-tagline {
    margin: 0;
    font-size: 14px;
    line-height: var(--line-height-relaxed);
    color: rgba(255, 255, 255, 0.84);
}

.footer-links-grid {
    display: grid;
    grid-template-columns: repeat(3, minmax(0, 1fr));
    gap: var(--space-5);
    margin-top: var(--space-3);
}

.footer-heading {
    font-family: var(--font-heading);
    font-size: 14px;
    letter-spacing: 0.16em;
    text-transform: uppercase;
    font-weight: var(--font-weight-semibold);
    margin: 0 0 var(--space-2);
    color: var(--color-primary-gold-soft);
}

.footer-links {
    display: flex;
    flex-direction: column;
    gap: 6px;
}

.footer-link-item {
    font-size: 14px;
}

.footer-link {
    color: rgba(255, 255, 255, 0.78);
    text-decoration: none;
    position: relative;
    padding-bottom: 2px;
    transition: color var(--transition-med);
}

.footer-link::after {
    content: '';
    position: absolute;
    left: 0;
    bottom: 0;
    width: 0;
    height: 1px;
    background-color: var(--color-primary-gold-soft);
    transition: width var(--transition-med);
}

.footer-link:hover {
    color: var(--color-primary-gold-soft);
}

.footer-link:hover::after {
    width: 100%;
}

.footer-bottom {
    margin-top: var(--space-5);
    padding-top: var(--space-3);
    border-top: 1px solid rgba(255, 255, 255, 0.08);
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: var(--space-2);
}

.footer-divider {
    width: 72px;
    height: 1px;
    background-color: rgba(244, 211, 122, 0.7);
}

.footer-copy {
    margin: 0;
    font-size: 12px;
    letter-spacing: 0.12em;
    text-transform: uppercase;
    color: rgba(255, 255, 255, 0.65);
}

/* =============================
   Responsive adjustments
   ============================= */

@media (max-width: 960px) {
    .header-top {
        flex-direction: column;
    }

    .header-logo-card {
        max-width: none;
        border-bottom: 1px solid rgba(0, 0, 0, 0.4);
    }

    .header-top-main {
        width: 100%;
    }

    .nav-list {
        justify-content: center;
        flex-wrap: wrap;
        gap: var(--space-2);
    }

    .footer-links-grid {
        grid-template-columns: repeat(2, minmax(0, 1fr));
    }
}

@media (max-width: 640px) {
    .layout-width {
        padding-left: var(--space-2);
        padding-right: var(--space-2);
    }

    .header-logo-card {
        padding: var(--space-3) var(--space-3) var(--space-2);
    }

    .nav-list {
        flex-direction: column;
        align-items: flex-start;
    }

    .footer-links-grid {
        grid-template-columns: 1fr;
    }

    .footer-top {
        gap: var(--space-3);
    }
}
